mapper.update:
UPDATE cart
SET quantity = #{quantity},
    selected = #{selected},
    update_time = #{updateTime}
WHERE id = #{id}

mapper.delete:
DELETE FROM cart
WHERE user_id = #{userId}
  AND drug_id = #{drugId}
  AND (specification_id = #{specificationId} OR (specification_id IS NULL AND #{specificationId} IS NULL))

DELETE FROM cart
WHERE user_id = #{userId}
AND (

    (drug_id = #{item.drugId}
    AND (specification_id = #{item.specificationId} OR (specification_id IS NULL AND #{item.specificationId} IS NULL)))

)

mapper.select:
SELECT * FROM cart
WHERE user_id = #{userId}
  AND drug_id = #{drugId}
  AND (specification_id = #{specificationId} OR (specification_id IS NULL AND #{specificationId} IS NULL))
